Schema field = m_schema.FindProperty("mac");
if (field == null)
  return;
aptixia.sm.tools.ChoiceListDlg dlg = new aptixia.sm.tools.ChoiceListDlg("mac");
dlg.Text = "Port CPU Filters (MAC Types)";
dlg.SetChoiceList(field.Choices);
dlg.SelectedChoices=mac;
if (dlg.ShowDialog(m_root) == DialogResult.OK)
{
      mac=dlg.SelectedChoices;
      CallSetters();
}

