string pname = "mac";
long min = 0;
long max = 0xFFFF;
Control ctrl = (Control) i_arg0;
string pvalue = ctrl.Text;

Schema schema = Schema.GetMetaSchema("FilterPlugin." + pname);
string error = Verifier.VerifyMultipleChoicesAndIntegerRanges(schema, pvalue, min, max);

if (error != null)
{
    error = "Incorrect values:" + error;
}

m_root.ErrorProvider.SetError(ctrl, error);

